+        if (randf(0,1)<0.2) id[i]= randi(0,INPUTSIZE); //20% of the brain AT LEAST should connect to input.
+        notted[i]= randf(0,1)<0.5;
+    }
+
+    type= (randf(0,1)>0.5)?(0):(1);
+    kp= randf(0.8,1);
