+void GLView::renderScene()
+{
+    glClear(GL_COLOR_BUFFER_BIT | GL_DEPTH_BUFFER_BIT);
+    glPushMatrix();
+
+    glTranslatef(conf::WWIDTH/2, conf::WHEIGHT/2, 0.0f);    
+    glScalef(scalemult, scalemult, 1.0f);
+    
+    if(following==0) {
+        glTranslatef(xtranslate, ytranslate, 0.0f);    
+    } else {
+        
+        float xi=0, yi=0;
