+        glTranslatef(-xi, -yi, 0.0f);
+        
+        //reset this if there is no interest. Probably agent that was followed died
+        if(xi==0 && yi==0) following = 0;
+    }
+    
+    world->draw(this, drawfood);
+
+    glPopMatrix();
+    glutSwapBuffers();
+}
