+void World::processMouse(int button, int state, int x, int y)
+{
+     if (state==0) {        
+         float mind=1e10;
+         float mini=-1;
+         float d;
+
+         for (int i=0;i<agents.size();i++) {
+             d= pow(x-agents[i].pos.x,2)+pow(y-agents[i].pos.y,2);
+                 if (d<mind) {
+                     mind=d;
+                     mini=i;
+                 }
+             }
