+void World::draw(View* view, bool drawfood)
+{
+    //draw food
+    if(drawfood) {
+        for(int i=0;i<FW;i++) {
+            for(int j=0;j<FH;j++) {
+                float f= 0.5*food[i][j]/conf::FOODMAX;
+                view->drawFood(i,j,f);
+            }
+        }
+    }
+    
+    //draw all agents
+    vector<Agent>::const_iterator it;
+    for ( it = agents.begin(); it != agents.end(); ++it) {
+        view->drawAgent(*it);
+    }
+    
+    view->drawMisc();
